import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  tasks: defineTable({
    text: v.string(),
    status: v.union(v.literal("todo"), v.literal("done")),
    runId: v.string(),
  }).index("by_run_id_and_status", ["runId", "status"]),
});

import { query, mutation } from "./_generated/server";
import { v } from "convex/values";

export const list = query({
  args: {
    runId: v.string(),
    status: v.optional(v.union(v.literal("todo"), v.literal("done"))),
  },
  handler: async (ctx, args) => {
    let q = ctx.db.query("tasks").withIndex("by_run_id_and_status", (q) => q.eq("runId", args.runId));
    if (args.status) {
      q = q.filter((q) => q.eq(q.field("status"), args.status));
      // Note: Convex indexes work best with equality on the first fields. 
      // Since we have ["runId", "status"], we could use:
      // q = ctx.db.query("tasks").withIndex("by_run_id_and_status", (q) => q.eq("runId", args.runId).eq("status", args.status));
      // Let's use that for efficiency if status is provided.
    }

    if (args.status) {
        return await ctx.db
            .query("tasks")
            .withIndex("by_run_id_and_status", (q) => 
                q.eq("runId", args.runId).eq("status", args.status)
            )
            .collect();
    }

    return await ctx.db
      .query("tasks")
      .withIndex("by_run_id_and_status", (q) => q.eq("runId", args.runId))
      .collect();
  },
});

export const add = mutation({
  args: {
    text: v.string(),
    runId: v.string(),
  },
  handler: async (ctx, args) => {
    await ctx.db.insert("tasks", {
      text: args.text,
      status: "todo",
      runId: args.runId,
    });
  },
});

export const updateStatus = mutation({
  args: {
    id: v.id("tasks"),
    status: v.union(v.literal("todo"), v.literal("done")),
  },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.id, { status: args.status });
  },
});

export const remove = mutation({
  args: {
    id: v.id("tasks"),
  },
  handler: async (ctx, args) => {
    await ctx.db.delete(args.id);
  },
});

import { useState } from 'react'
import { useQuery, useMutation } from "convex/react";
import { api } from "../convex/_generated/api";
import './App.css'

const RUN_ID = import.meta.env.VITE_ZEALT_RUN_ID;

function App() {
  const [newTaskText, setNewTaskText] = useState("");
  const tasks = useQuery(api.tasks.list, { runId: RUN_ID });
  const addTask = useMutation(api.tasks.add);
  const updateStatus = useMutation(api.tasks.updateStatus);
  const deleteTask = useMutation(api.tasks.remove);

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskText.trim()) return;
    await addTask({ text: newTaskText, runId: RUN_ID });
    setNewTaskText("");
  };

  return (
    <div className="App">
      <h1>Task Manager</h1>
      <form onSubmit={handleAddTask}>
        <input
          type="text"
          value={newTaskText}
          onChange={(e) => setNewTaskText(e.target.value)}
          placeholder="New task..."
        />
        <button type="submit">Add Task</button>
      </form>

      <ul>
        {tasks?.map((task) => (
          <li key={task._id}>
            <span style={{ textDecoration: task.status === "done" ? "line-through" : "none" }}>
              {task.text}
            </span>
            <button
              onClick={() =>
                updateStatus({
                  id: task._id,
                  status: task.status === "todo" ? "done" : "todo",
                })
              }
            >
              {task.status === "todo" ? "Mark Done" : "Mark Todo"}
            </button>
            <button onClick={() => deleteTask({ id: task._id })}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default App

